+            info: TaskInfo {
+                id: task_id,
+                task_type: "t".to_string(),
+                status: TaskStatus::Running,
+                progress: None,
+                message: None,
+                created_at: String::new(),
+                started_at: None,
+                completed_at: None,
+                error: None,
+            },
+            cancel_requested: false,
+            result: None,
+            cx: Cx::for_testing(),
+        };
+        // Same state transition returns true
